class Driver;
  virtual my_if vif;
  task run();
    vif.set_period(5ns);
    vif.start_clk();
  endtask
endclass

function void start_clk();
  if (clk_period) clk_active = 1;
endfunction

interface my_if();
  bit clk_active = 0;
  realtime clk_period;
  initial wait (clk_active);
  always @* begin
    if (clk_period == 0.0) automatic process p = process::self();
  end
  function void start_clk();
    if (clk_period) clk_active = 1;
  endfunction
endinterface
